```rust
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(default)]
pub struct SelfHealingConfig {
    /// When hook fails to connect to daemon, try to start it
    pub hook_starts_daemon: bool,

    /// When daemon starts, install Claude Code hook if missing
    pub daemon_installs_hooks: bool,

    /// Max seconds to wait for daemon to start
    pub daemon_start_timeout: u32,

    /// Min seconds between auto-start attempts
    pub auto_start_cooldown: u32,

    /// Log level for self-healing operations
    pub self_healing_log_level: String,
}

impl Default for SelfHealingConfig {
    fn default() -> Self {
        Self {
            hook_starts_daemon: true,
            daemon_installs_hooks: true,
            daemon_start_timeout: 3,
            auto_start_cooldown: 30,
            self_healing_log_level: "info".to_string(),
        }
    }
}

impl SelfHealingConfig {
    /// Apply environment variable overrides
    pub fn with_env_overrides(mut self) -> Self {
        if let Ok(val) = std::env::var("RCH_HOOK_STARTS_DAEMON") {
            self.hook_starts_daemon = val != "0" && val.to_lowercase() != "false";
        }
        if let Ok(val) = std::env::var("RCH_DAEMON_INSTALLS_HOOKS") {
            self.daemon_installs_hooks = val != "0" && val.to_lowercase() != "false";
        }
        if let Ok(val) = std::env::var("RCH_DAEMON_START_TIMEOUT") {
            if let Ok(secs) = val.parse() {
                self.daemon_start_timeout = secs;
            }
        }
        if let Ok(val) = std::env::var("RCH_AUTO_START_COOLDOWN") {
            if let Ok(secs) = val.parse() {
                self.auto_start_cooldown = secs;
            }
        }
        if let Ok(val) = std::env::var("RCH_SELF_HEALING_LOG_LEVEL") {
            self.self_healing_log_level = val;
        }
        // Master disable switch
        if let Ok(val) = std::env::var("RCH_NO_SELF_HEALING") {
            if val == "1" || val.to_lowercase() == "true" {
                self.hook_starts_daemon = false;
                self.daemon_installs_hooks = false;
            }
        }
        self
    }
}
```

